mapper.select:
SELECT id::text AS chunk_id, CAST(metadata->>'doc_id' AS BIGINT) AS document_id, COALESCE(CAST(metadata->>'chunk_index' AS INTEGER), 0) AS chunk_index, COALESCE(metadata->>'filename', 'unknown') AS filename, metadata->>'chunk_preview' AS preview, content, (
( CASE WHEN LOWER(COALESCE(metadata->>'filename', '')) LIKE CONCAT('%', LOWER(#{term}), '%') THEN 3 ELSE 0 END + CASE WHEN LOWER(COALESCE(metadata->>'chunk_preview', '')) LIKE CONCAT('%', LOWER(#{term}), '%') THEN 2 ELSE 0 END + CASE WHEN LOWER(content) LIKE CONCAT('%', LOWER(#{term}), '%') THEN 1 ELSE 0 END )
) AS lexical_score FROM vector_store WHERE metadata->>'kb_id' = CAST(#{knowledgeBaseId} AS TEXT) AND (
LOWER(content) LIKE CONCAT('%', LOWER(#{term}), '%') OR LOWER(COALESCE(metadata->>'chunk_preview', '')) LIKE CONCAT('%', LOWER(#{term}), '%') OR LOWER(COALESCE(metadata->>'filename', '')) LIKE CONCAT('%', LOWER(#{term}), '%')
) ORDER BY lexical_score DESC, COALESCE(CAST(metadata->>'chunk_index' AS INTEGER), 0) ASC, id ASC LIMIT #{limit}
